console.log(add(3));

次のコードで counter() を2回呼び出したとき、2回目の console.log の結果として正しいものはどれですか？

function makeCounter() {
  let count = 0;
  return function() {
    count++;
    return count;
  };
}
const counter = makeCounter();
console.log(counter());
console.log(counter());

